mapper.update:
update ${sourceTable}


        circulation_type = #{circulationType},


        update_user = #{userId},


        update_time = #{updateTime},


where organization_id = #{orgId}

mapper.select:
select id, origin_id, target_id, enable, field_config, module_type
from stage_advanced_config
where organization_id = #{orgId}
  and module_type = #{moduleType}

select id, name, type, afoot_roll_back, end_roll_back, circulation_type, pos
from ${sourceTable}
where id = #{id}

select id, enable, field_config
from stage_advanced_config
where origin_id = #{originId}
  and target_id = #{targetId}
  and module_type = #{moduleType}
